class SketchBasedJoinEstimatorBudgetAndSliceRegressionTest {

	private static final ValueFactory VF = SimpleValueFactory.getInstance();

	@Test
	void overBudgetDirtySketchesUnloadWhenPersistenceIsDisabled() throws Exception {
		IRI predicate = VF.createIRI("urn:p");
		SketchBasedJoinEstimator estimator = new SketchBasedJoinEstimator(new StubSailStore(), config());
		setSketchBudgetBytes(estimator, 0L, 0L);

		estimator.addStatement(st(VF.createIRI("urn:s"), predicate, VF.createIRI("urn:o")));
		flushIncrementalBuffer(estimator);

		assertTrue(estimator.debugResidentSketches().isEmpty(),
				"Over-budget dirty sketches should not remain resident without persistence");
		assertFalse(estimator.isReady(),
				"Estimator should fall back until rebuild after dropping dirty sketches without persistence");
	}

	@Test
	void slicePlanEstimateClampsVariableDistinctCountsToLimitedRows() {
		IRI predicate = VF.createIRI("urn:hasObservation");
		StubSailStore store = new StubSailStore();
		for (int i = 0; i < 200; i++) {
			store.add(st(VF.createIRI("urn:encounter:" + i), predicate, VF.createIRI("urn:observation:" + i)));
		}

		SketchBasedJoinEstimator estimator = new SketchBasedJoinEstimator(store, config());
		estimator.rebuildOnceSlow();

		StatementPattern pattern = new StatementPattern(Var.of("enc"), Var.of("p", predicate), Var.of("obs"));
		Slice slice = new Slice(pattern, 0L, 1L);
		SketchBasedJoinEstimator.TuplePlanEstimate estimate = estimator.planEstimateForJoinOrdering(slice, Set.of());

		assertNotNull(estimate, "Expected planner estimate for slice");
		assertEquals(1.0d, estimate.outputRows(), 0.0d);
		assertTrue(distinct(varStats(estimate).get("enc")) <= estimate.outputRows(),
				"Slice should cap subject distinct count at surviving row count");
		assertTrue(distinct(varStats(estimate).get("obs")) <= estimate.outputRows(),
				"Slice should cap object distinct count at surviving row count");
	}

	private static Statement st(Resource s, IRI p, Value o) {
		return VF.createStatement(s, p, o);
	}

	private static SketchBasedJoinEstimator.Config config() {
		return SketchBasedJoinEstimator.Config.defaults()
				.withNominalEntries(64)
				.withThrottleEveryN(1)
				.withThrottleMillis(0)
				.withRefreshSleepMillis(5);
	}

	private static void flushIncrementalBuffer(SketchBasedJoinEstimator estimator) {
		estimator.debugFlushPendingIncremental();
	}

	private static void setSketchBudgetBytes(SketchBasedJoinEstimator estimator, long minBytes, long maxBytes)
			throws Exception {
		Field minField = SketchBasedJoinEstimator.class.getDeclaredField("minSketchMemoryBytes");
		Field maxField = SketchBasedJoinEstimator.class.getDeclaredField("maxSketchMemoryBytes");
		minField.setAccessible(true);
		maxField.setAccessible(true);
		minField.setLong(estimator, minBytes);
		maxField.setLong(estimator, maxBytes);
	}

	@SuppressWarnings("unchecked")
	private static Map<String, Object> varStats(SketchBasedJoinEstimator.TuplePlanEstimate estimate) {
		try {
			Field field = SketchBasedJoinEstimator.TuplePlanEstimate.class.getDeclaredField("varStats");
			field.setAccessible(true);
			return (Map<String, Object>) field.get(estimate);
		} catch (ReflectiveOperationException e) {
			throw new AssertionError(e);
		}
	}

	private static double distinct(Object varPlanStats) {
		assertNotNull(varPlanStats, "Expected variable stats");
		try {
			Field field = varPlanStats.getClass().getDeclaredField("distinct");
			field.setAccessible(true);
			return field.getDouble(varPlanStats);
		} catch (ReflectiveOperationException e) {
			throw new AssertionError(e);
		}
	}
}
